Here is the C++ program to read a text file line by line and count the number of occurrences of a specific word in the file:

```cpp
#include <iostream>
#include <fstream>
#include <string>
using namespace std;

int main() {
    ifstream file("input.txt");
    string wordToSearch = "example";
    string line;
    int wordCount = 0;

    if (file.is_open()) {
        while (getline(file, line)) {
            size_t pos = 0;
            while ((pos = line.find(wordToSearch, pos)) != string::npos) {
                wordCount++;
                pos += wordToSearch.size();
            }
        }
        file.close();
    } else {
        cout << "Unable to open file" << endl;
        return 1;
    }

    cout << "The word '" << wordToSearch << "' occurs " << wordCount << " times in the file." << endl;

    return 0;
}
```

This program reads the text file "input.txt" line by line and searches for the word "example". It counts the number of occurrences of the word and then displays the count. Make sure to replace "input.txt" with the actual name of your input file.
